```scss
html.dark {
  // 覆盖自定义组件的暗色模式变量
  --mfw-component-bg: var(--el-bg-color-overlay);
  --mfw-component-border: var(--el-border-color-darker);

  // 覆盖业务组件特定样式
  .mfw-detail-panel {
