    }, () => row.status === STATUS.ENABLED ? '启用' : '禁用'),
  },
  { prop: 'createdAt', label: '创建时间', width: 180,
    render: ({ row }) => h(MfwDateFormat, { value: row.createdAt }),
  },
];

const actionColumn = {
  prop: 'action', label: '操作', width: 200, fixed: 'right' as const,
  render: ({ row }) => renderActionButtons([
