  --mfw-component-border: var(--el-border-color-darker);

  // 覆盖业务组件特定样式
  .mfw-detail-panel {
    --mfw-detail-bg: var(--el-bg-color-overlay);
    --mfw-detail-border: var(--el-border-color-darker);
  }
}
```

